export const getChaptersForSubject = (classSlug: string, subjectSlug: string) => {
  const key = `${classSlug}-${subjectSlug}`;
  return chapterData[key] || [];
};

export const getExercisesForChapter = (classSlug: string, subjectSlug: string, chapterSlug: string) => {
  const key = `${classSlug}-${subjectSlug}-${chapterSlug}`;
  return exerciseData[key] || [];
};

export const getChapterBySlug = (classSlug: string, subjectSlug: string, chapterSlug: string) => {
  const chapters = getChaptersForSubject(classSlug, subjectSlug);
  return chapters.find(c => c.slug === chapterSlug);
};

export const getExerciseBySlug = (classSlug: string, subjectSlug: string, chapterSlug: string, exerciseSlug: string) => {
  const exercises = getExercisesForChapter(classSlug, subjectSlug, chapterSlug);
  return exercises.find(e => e.slug === exerciseSlug);
};








